// Reglas simples y prácticas por tipo/clase:
export function buildSlotsFromBrands(brands) {
  const has = pred => brands.some(pred);
  const slots = [];
  // PRANDIAL: ultrarrápida/rápida => bolus en comidas principales
  if (has(b => b.class === 'prandial')) {
    slots.push({
      id: 'morning',
      label: 'Mañana',
      startMin: 6 * 60,
      endMin: 12 * 60,
      kind: 'bolus'
    });
    slots.push({
      id: 'afternoon',
      label: 'Tarde',
      startMin: 12 * 60,
      endMin: 18 * 60,
      kind: 'bolus'
    });
    // si tu madre también usa cena, añade:
    // slots.push({ id:'evening', label:'Cena', startMin:18*60, endMin:22*60, kind:'bolus' });
  }
  // BASAL PROLONGADA: una dosis/día (de noche por defecto)
  if (has(b => b.class === 'basal' && b.speed === 'prolongada')) {
    slots.push({
      id: 'basal_night',
      label: 'Basal noche',
      startMin: 18 * 60,
      endMin: 24 * 60 - 1,
      kind: 'basal'
    });
  }
  // BASAL INTERMEDIA (NPH): típicamente 2 dosis (mañana y noche)
  if (has(b => b.class === 'basal' && b.speed === 'intermedia')) {
    slots.push({
      id: 'nph_morning',
      label: 'NPH mañana',
      startMin: 6 * 60,
      endMin: 12 * 60,
      kind: 'basal'
    });
    slots.push({
      id: 'nph_night',
      label: 'NPH noche',
      startMin: 18 * 60,
      endMin: 24 * 60 - 1,
      kind: 'basal'
    });
  }
  // MEZCLAS: dos tomas (desayuno/comida)
  if (has(b => b.class === 'mix')) {
    slots.push({
      id: 'mix_morning',
      label: 'Mezcla mañana',
      startMin: 6 * 60,
      endMin: 12 * 60,
      kind: 'both'
    });
    slots.push({
      id: 'mix_afternoon',
      label: 'Mezcla tarde',
      startMin: 12 * 60,
      endMin: 18 * 60,
      kind: 'both'
    });
  }
  // fallback por si no quedó nada (evita pantalla vacía)
  if (slots.length === 0) {
    slots.push({
      id: 'morning',
      label: 'Mañana',
      startMin: 6 * 60,
      endMin: 12 * 60,
      kind: 'both'
    });
  }
  return slots;
}
